import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  getAllSupportsApi,
  getMySupportsApi,
  updateSupportStatusApi
} from '../api/apiServices';

const RequestList = () => {
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState('ALL');
  const [statusFilter, setStatusFilter] = useState('ALL');
  const [requests, setRequests] = useState([]);
  const [myRequests, setMyRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedReq, setSelectedReq] = useState(null);

  const currentUser = JSON.parse(localStorage.getItem('user') || '{}');

  const getStatusLabel = (status) => {
    switch (status) {
      case 'PENDING':
        return 'Chờ xử lý';
      case 'ASSIGNED':
        return 'Đã phân công';
      case 'IN_PROGRESS':
        return 'Đang hỗ trợ';
      case 'RESOLVED':
        return 'Đã hoàn thành';
      case 'CANCELLED':
        return 'Đã hủy';
      default:
        return status;
    }
  };

  const getStatusStyle = (status) => {
    switch (status) {
      case 'PENDING':
        return {
          background: '#FEF3C7',
          color: '#B45309'
        };
      case 'ASSIGNED':
        return {
          background: '#DBEAFE',
          color: '#1D4ED8'
        };
      case 'IN_PROGRESS':
        return {
          background: '#E0F2FE',
          color: '#0369A1'
        };
      case 'RESOLVED':
        return {
          background: '#DCFCE7',
          color: '#15803D'
        };
      case 'CANCELLED':
        return {
          background: '#FEE2E2',
          color: '#B91C1C'
        };
      default:
        return {
          background: '#E2E8F0',
          color: '#475569'
        };
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);

    try {
      const [allRes, myRes] = await Promise.all([
        getAllSupportsApi().catch(() => ({ data: [] })),
        getMySupportsApi().catch(() => ({ data: [] }))
      ]);

      setRequests(allRes.data || []);
      setMyRequests(myRes.data || []);
    } catch (err) {
      console.error(err);
    }

    setLoading(false);
  };

  const getFilteredRequests = () => {
    let list = [];

    if (activeTab === 'ALL') {
      list = [...requests];
    } else if (activeTab === 'MINE') {
      list = [...myRequests];
    } else {
      const myIds = new Set(myRequests.map((r) => r.id));
      list = requests.filter((r) => !myIds.has(r.id));
    }

    if (statusFilter !== 'ALL') {
      list = list.filter((r) => r.status === statusFilter);
    }

    return list.sort(
      (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
    );
  };

  const filtered = getFilteredRequests();

  const handleUpdateStatus = async (id, newStatus) => {
    try {
      await updateSupportStatusApi(id, newStatus);
      await fetchData();
      setSelectedReq(null);
    } catch (err) {
      console.error(err);
      alert('Cập nhật trạng thái thất bại');
    }
  };

  const handleOpenMap = (req) => {
    navigate('/', {
      state: {
        routeToDest: {
          lat: req.latitude,
          lng: req.longitude
        }
      }
    });
  };

  return (
    <div className="container" style={{ paddingTop: '32px', paddingBottom: '40px' }}>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '28px'
        }}
      >
        <h2
          style={{
            margin: 0,
            fontSize: '2rem',
            fontWeight: '800',
            color: '#0F172A'
          }}
        >
          Danh sách yêu cầu
        </h2>
      </div>

      <div
        style={{
          display: 'flex',
          gap: '12px',
          flexWrap: 'wrap',
          marginBottom: '28px',
          alignItems: 'center'
        }}
      >
        <button
          className={`btn ${activeTab === 'ALL' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('ALL')}
        >
          Tất cả
        </button>

        <button
          className={`btn ${activeTab === 'MINE' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('MINE')}
        >
          Yêu cầu của tôi
        </button>

        <button
          className={`btn ${activeTab === 'OTHERS' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('OTHERS')}
        >
          Người khác
        </button>

        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          style={{
            marginLeft: 'auto',
            padding: '10px 14px',
            borderRadius: '10px',
            border: '1px solid #CBD5E1',
            outline: 'none',
            background: 'white',
            color: '#334155',
            fontWeight: '500'
          }}
        >
          <option value="ALL">Mọi trạng thái</option>
          <option value="PENDING">Chờ xử lý</option>
          <option value="ASSIGNED">Đã phân công</option>
          <option value="IN_PROGRESS">Đang hỗ trợ</option>
          <option value="RESOLVED">Đã hoàn thành</option>
          <option value="CANCELLED">Đã hủy</option>
        </select>
      </div>

      {loading ? (
        <p style={{ color: '#64748B' }}>Đang tải dữ liệu...</p>
      ) : filtered.length === 0 ? (
        <div
          style={{
            background: 'white',
            borderRadius: '16px',
            padding: '40px',
            textAlign: 'center',
            color: '#94A3B8',
            border: '1px solid #E2E8F0'
          }}
        >
          Không có yêu cầu phù hợp.
        </div>
      ) : (
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))',
            gap: '20px'
          }}
        >
          {filtered.map((r) => {
            const isMine = myRequests.some((m) => m.id === r.id);

            return (
              <div
                key={r.id}
                onClick={() => setSelectedReq({ ...r, isMine })}
                style={{
                  background: '#fff',
                  borderRadius: '18px',
                  padding: '24px',
                  border: '1px solid #E2E8F0',
                  boxShadow: '0 8px 24px rgba(15,23,42,0.06)',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease'
                }}
              >
                <div
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'flex-start',
                    marginBottom: '16px'
                  }}
                >
                  <div
                    style={{
                      fontSize: '1.8rem',
                      fontWeight: '800',
                      color: '#1E3A5F'
                    }}
                  >
                    {r.requestType}
                  </div>

                  <span
                    style={{
                      ...getStatusStyle(r.status),
                      padding: '8px 14px',
                      borderRadius: '999px',
                      fontSize: '0.85rem',
                      fontWeight: '700'
                    }}
                  >
                    {getStatusLabel(r.status)}
                  </span>
                </div>

                <div
                  style={{
                    color: '#64748B',
                    fontSize: '1rem',
                    minHeight: '54px',
                    marginBottom: '18px',
                    lineHeight: 1.6
                  }}
                >
                  {r.description}
                </div>

                <div
                  style={{
                    display: 'flex',
                    gap: '20px',
                    color: '#94A3B8',
                    fontSize: '0.95rem',
                    marginBottom: '14px'
                  }}
                >
                  <span>👥 {r.numberOfPeople} người</span>
                  <span>
                    📅{' '}
                    {r.createdAt
                      ? new Date(r.createdAt).toLocaleDateString('vi-VN')
                      : ''}
                  </span>
                </div>

                {isMine && (
                  <div
                    style={{
                      color: '#2563EB',
                      fontWeight: '700',
                      fontSize: '0.95rem'
                    }}
                  >
                    YÊU CẦU CỦA BẠN
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {selectedReq && (
        <div
          onClick={() => setSelectedReq(null)}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(15,23,42,0.55)',
            backdropFilter: 'blur(4px)',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            zIndex: 9999,
            padding: '24px'
          }}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: '#fff',
              width: '100%',
              maxWidth: '620px',
              borderRadius: '20px',
              padding: '32px',
              boxShadow: '0 25px 50px rgba(0,0,0,0.15)'
            }}
          >
            <div
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                marginBottom: '24px'
              }}
            >
              <h3
                style={{
                  margin: 0,
                  fontSize: '1.7rem',
                  fontWeight: '800',
                  color: '#0F172A'
                }}
              >
                Chi tiết yêu cầu
              </h3>

              <button
                onClick={() => setSelectedReq(null)}
                style={{
                  background: 'transparent',
                  border: 'none',
                  fontSize: '1.6rem',
                  cursor: 'pointer',
                  color: '#64748B'
                }}
              >
                ×
              </button>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <div>
                <strong>Loại hỗ trợ:</strong> {selectedReq.requestType}
              </div>

              <div>
                <strong>Trạng thái:</strong>{' '}
                <span
                  style={{
                    ...getStatusStyle(selectedReq.status),
                    padding: '6px 12px',
                    borderRadius: '999px',
                    fontSize: '0.85rem',
                    fontWeight: '700'
                  }}
                >
                  {getStatusLabel(selectedReq.status)}
                </span>
              </div>

              <div>
                <strong>Số người:</strong> {selectedReq.numberOfPeople}
              </div>

              <div>
                <strong>Tọa độ:</strong>{' '}
                {selectedReq.latitude?.toFixed(4)},{' '}
                {selectedReq.longitude?.toFixed(4)}
              </div>

              <div>
                <strong>Ngày tạo:</strong>{' '}
                {selectedReq.createdAt
                  ? new Date(selectedReq.createdAt).toLocaleString('vi-VN')
                  : ''}
              </div>

              <div>
                <strong>Mô tả:</strong>
                <div
                  style={{
                    marginTop: '8px',
                    background: '#F8FAFC',
                    border: '1px solid #E2E8F0',
                    borderRadius: '12px',
                    padding: '14px',
                    color: '#475569',
                    lineHeight: 1.6
                  }}
                >
                  {selectedReq.description}
                </div>
              </div>
            </div>

            <div
              style={{
                marginTop: '32px',
                display: 'flex',
                gap: '12px',
                flexWrap: 'wrap'
              }}
            >
              <button
                className="btn btn-outline"
                onClick={() => setSelectedReq(null)}
              >
                Đóng
              </button>

              {selectedReq.isMine ? (
                selectedReq.status === 'PENDING' && (
                  <button
                    className="btn btn-danger"
                    onClick={() =>
                      handleUpdateStatus(selectedReq.id, 'CANCELLED')
                    }
                  >
                    Hủy yêu cầu
                  </button>
                )
              ) : (
                <>
                  <button
                    className="btn btn-primary"
                    onClick={() => handleOpenMap(selectedReq)}
                  >
                    Xem trên bản đồ
                  </button>

                  {selectedReq.status === 'PENDING' &&
                    currentUser.role !== 'CITIZEN' && (
                      <button
                        onClick={() =>
                          handleUpdateStatus(selectedReq.id, 'ASSIGNED')
                        }
                        style={{
                          background: '#10B981',
                          color: '#fff',
                          border: 'none',
                          borderRadius: '10px',
                          padding: '12px 18px',
                          fontWeight: '700',
                          cursor: 'pointer'
                        }}
                      >
                        Đến giúp
                      </button>
                    )}
                </>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
export default RequestList;
